DarkRPUI.HUD.RegisterElement("ammo",{paint=function(ply) local wpn=IsValid(ply) and ply:GetActiveWeapon(); if not IsValid(wpn) or wpn:Clip1()<0 then return end local sx,sy,sw,sh=DarkRPUI.Layout.GetSafeRect(); local x,y=DarkRPUI.Layout.ClampRect(sx+sw-205,sy+sh-76,205,76,true); DarkRPUI.UI.ShadowedBox(18,x,y,205,76,DarkRPUI.WithAlpha(DarkRPUI.Color("panel"),235),DarkRPUI.Color("border"),105); DarkRPUI.UI.Text(wpn:Clip1().." / "..ply:GetAmmoCount(wpn:GetPrimaryAmmoType()),"DarkRPUI.Number",x+190,y+12,DarkRPUI.Color("text"),TEXT_ALIGN_RIGHT) end})
